<?php echo "--- NODES ---" . PHP_EOL; $nodes = \App\Models\BlNode::where("metadata", "LIKE", "%Phi-l%")->get(); foreach ($nodes as $n) { echo "- ID: " . $n->id . " | Label: " . $n->label . " | Group: " . $n->group . " | Metadata: " . json_encode($n->metadata) . PHP_EOL; } echo "--- EDGES ---" . PHP_EOL; $edges = \App\Models\BlEdge::where("metadata", "LIKE", "%Phi-l%")->get(); foreach ($edges as $e) { echo "- Src ID: " . $e->source_node_id . " -> Trg ID: " . $e->target_node_id . " | Rel: " . $e->relationship . " | Metadata: " . json_encode($e->metadata) . PHP_EOL; }
